import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common'; // 🚀 Indispensable pour injecter NgClass et les Pipes de dates

@Component({
  selector: 'app-applications-list',
  standalone: true,
  imports: [CommonModule], // ngClass est hébergé ici
  templateUrl: './applications-list.component.html',
  styleUrls: ['./applications-list.component.css']
})
export class ApplicationsListComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  historyList: any[] = [];
  isLoading: boolean = true;

  ngOnInit() {
    this.fetchCandidateHistory();
  }

  fetchCandidateHistory() {
    const targetUrl = 'http://localhost:3000/api/candidate/history';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de lire votre historique.");
      return res.json();
    })
    .then(data => {
      // Stocke le tableau history retourné par l'API
      this.historyList = data.history || [];
      this.isLoading = false;
      this.cdr.detectChanges(); // Met à jour l'interface Tailwind instantanément
    })
    .catch(err => {
      console.error("Erreur historique candidat :", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }
}
<div class="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 w-full font-sans text-xs">
  <h3 class="text-base font-bold text-slate-900 mb-3 flex items-center">
    <span class="mr-2">📥</span> Suivi de mes candidatures
  </h3>
  
  <table class="w-full text-left border-collapse">
    <thead>
      <tr class="bg-slate-50 border-b border-slate-200 font-bold text-slate-500 uppercase tracking-wider text-[11px]">
        <th class="p-3 pl-4">Poste / Entreprise</th>
        <th class="p-3">Date d'envoi</th>
        <th class="p-3 pr-4">Statut</th>
      </tr>
    </thead>
    <tbody class="divide-y divide-slate-100 font-medium text-slate-700">
      
      <!-- ⏳ ÉTAT DE CHARGEMENT ASYNCHRONE -->
      @if (isLoading) {
        <tr>
          <td colspan="3" class="p-6 text-center text-slate-400 font-semibold">
            <i class="bi bi-arrow-clockwise inline-block animate-spin mr-2 text-sm text-sky-500"></i>
            Chargement de votre historique...
          </td>
        </tr>
      }

      <!-- 🚫 CAS DU PIPELINE VIDE -->
      @if (!isLoading && historyList.length === 0) {
        <tr>
          <td colspan="3" class="p-8 text-center text-slate-400 font-semibold">
            <i class="bi bi-send-x-fill block text-xl mb-1 text-slate-300"></i>
            Vous n'avez pas encore envoyé de candidatures.
          </td>
        </tr>
      }

      <!-- 🚀 RENDU DYNAMIQUE DES LIGNES MYSQL -->
      @for (app of historyList; track app.job_id) {
        <tr class="hover:bg-slate-50/40 transition-colors">
          <td class="p-3 pl-4">
            <span class="block font-bold text-slate-900 text-sm">{{ app.job_title }}</span>
            <span class="text-xs font-semibold text-emerald-600 uppercase flex items-center">🏢 {{ app.company_name }}</span>
          </td>
          <td class="p-3 text-slate-500 font-semibold">📅 {{ app.applied_at | date:'dd/MM/yyyy' }}</td>
          <td class="p-3 pr-4">
            <!-- 🌟 BADGES MULTICOULEURS COMPATIBLES AVEC L'ATS RECRUTEUR & HEIDISQL -->
            <span [ngClass]="{
              'bg-amber-50 text-amber-700 border-amber-200': app.status === 'Nouveau' || app.status === 'en_attente',
              'bg-blue-50 text-blue-700 border-blue-200': app.status === 'Entretien',
              'bg-emerald-50 text-emerald-700 border-emerald-200': app.status === 'retenu' || app.status === 'Acceptée',
              'bg-red-50 text-red-700 border-red-200': app.status === 'refuse' || app.status === 'Refusée'
            }" class="inline-flex items-center px-2.5 py-0.5 rounded-full border font-bold text-[10px] uppercase tracking-wide">
              {{ app.status === 'Nouveau' || app.status === 'en_attente' ? 'En attente' : app.status === 'retenu' ? 'Retenu' : app.status === 'refuse' ? 'Refusé' : app.status }}
            </span>
          </td>
        </tr>
      }
      
    </tbody>
  </table>
</div>
